#include <iostream>
#include <iomanip>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<vector<int>> a(N, vector<int>(N, 0));

    int num = 1;
    // Fill along anti-diagonals (sum i+j constant) starting from top-right
    // The order: for each diagonal sum s from N-1 down to 0 (top-right to bottom-left),
    // then from s=N up to 2*(N-1) (but actually let's trace the pattern)
    //
    // For N=5, the pattern from sample:
    // Row 0: 15 16 22 23 25
    // Row 1:  7 14 17 21 24
    // Row 2:  6  8 13 18 20
    // Row 3:  2  5  9 12 19
    // Row 4:  1  3  4 10 11
    //
    // The order of filling is along diagonals (constant i+j) going from
    // top-right (smallest i+j?) to bottom-left.
    // Let's map:
    // i+j = 4: (0,4)=1, (1,3)=2, (2,2)=3, (3,1)=4, (4,0)=5  -> but sample has these at end
    // Actually need to figure out the exact pattern.
    //
    // Let's re-examine sample output:
    // Row0: 15 16 22 23 25
    // Row1:  7 14 17 21 24
    // Row2:  6  8 13 18 20
    // Row3:  2  5  9 12 19
    // Row4:  1  3  4 10 11
    //
    // Let's map positions to values (1-indexed position in fill order):
    // Position 1 -> (4,0) = 1
    // Position 2 -> (3,0) = 2
    // Position 3 -> (4,1) = 3
    // Position 4 -> (4,2) = 4
    // Position 5 -> (3,1) = 5
    // Position 6 -> (2,0) = 6
    // Position 7 -> (1,0) = 7
    // Position 8 -> (2,1) = 8
    // Position 9 -> (3,2) = 9
    // Position 10 -> (4,3) = 10
    // Position 11 -> (4,4) = 11
    // Position 12 -> (3,3) = 12
    // Position 13 -> (2,2) = 13
    // Position 14 -> (1,1) = 14
    // Position 15 -> (0,0) = 15
    // Position 16 -> (0,1) = 16
    // Position 17 -> (1,2) = 17
    // Position 18 -> (2,3) = 18
    // Position 19 -> (3,4) = 19
    // Position 20 -> (2,4) = 20
    // Position 21 -> (1,3) = 21
    // Position 22 -> (0,2) = 22
    // Position 23 -> (0,3) = 23
    // Position 24 -> (1,4) = 24
    // Position 25 -> (0,4) = 25
    //
    // The pattern: fill along diagonals from NE to SW.
    // Let's group by (i+j) sum:
    // sum=0: (0,0)=15   (diagonal from (0,0))
    // sum=1: (0,1)=16, (1,0)=7
    // sum=2: (0,2)=22, (1,1)=14, (2,0)=6
    // sum=3: (0,3)=23, (1,2)=17, (2,1)=8, (3,0)=2
    // sum=4: (0,4)=25, (1,3)=21, (2,2)=13, (3,1)=5, (4,0)=1
    // sum=5: (1,4)=24, (2,3)=18, (3,2)=9, (4,1)=3
    // sum=6: (2,4)=20, (3,3)=12, (4,2)=4
    // sum=7: (3,4)=19, (4,3)=10
    // sum=8: (4,4)=11
    //
    // So we fill diagonals (constant i+j) in order of increasing sum.
    // Within each diagonal, we fill from bottom to top (increasing i, decreasing j).
    // But wait - for sum=1: (1,0) then (0,1) -> that's bottom to top? i goes 1 then 0.
    // For sum=2: (2,0), (1,1), (0,2) -> yes bottom to top.
    //
    // Let's verify: sum=0: (0,0)=15 - only one.
    // sum=1: started at (1,0)=7, then (0,1)=16. Bottom to top.
    // sum=2: (2,0)=6, (1,1)=14, (0,2)=22. Bottom to top.
    // Yes, fill from bottom to top along each diagonal (constant i+j).
    // Diagonals processed in increasing order of sum (0 to 2*(N-1)).

    for (int sum = 0; sum <= 2 * (N - 1); ++sum) {
        // Start from bottom: i = min(N-1, sum), j = sum - i
        // Go while i >= 0 and j < N
        int i_start = min(N - 1, sum);
        int j_start = sum - i_start;

        for (int i = i_start; i >= 0 && (sum - i) < N; --i) {
            int j = sum - i;
            a[i][j] = num++;
        }
    }

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            cout << setw(3) << a[i][j];
        }
        cout << '\n';
    }

    return 0;
}
